body.script:
//><!--

   Ext.USE_NATIVE_JSON = true;
   Ext.BLANK_IMAGE_URL = '/identityiq-8.4/scripts/ext-4.1.0/resources/themes/images/default/tree/s.gif';
   SailPoint.CONTEXT_PATH = '/identityiq-8.4';
   SailPoint.SESSION_TIMEOUT = 28800000;

   /**
   * Overrides for the Date formats used by ext. We have standard formats
   * we use on the server side. The formats are localized, then converted to use
   * the js format symbols.
   */
   SailPoint.DateFormat = 'n\/d\/Y';
   SailPoint.TimeFormat = 'h:i:s a';
   SailPoint.DateTimeFormat = 'n\/d\/Y h:i:s a';

   // Flag to indicate whether our session & CSRF cookies should be secure.
   SailPoint.isSecure = false;
   // Have to use document.cookie directly, since ExtJS doesn't support SameSite attribute.
   var cookieDef = 'CSRF-TOKEN=VTllJWxDWjiJMJ9voNNkvIYuagK0CoJajwp+1IBDFxc=; path=/identityiq-8.4; samesite=lax';
   if (SailPoint.isSecure) {
       cookieDef += '; secure';
   }
   document.cookie = cookieDef;

//--><!

// Stored here so it can be easily accessed globally
SailPoint.CURR_DISPLAYABLE_USER_NAME = "The Administrator";
